import React, { createContext, useContext, useState, useCallback } from 'react';
import { v4 as uuidv4 } from 'uuid';

const INITIAL_TASKS = [
  {
    id: uuidv4(),
    title: 'Set up NestJS project',
    description: 'Run `nest new task-manager`, configure TypeORM and SQLite',
    status: 'done',
    created_at: '2026-03-18',
  },
  {
    id: uuidv4(),
    title: 'Create Task module',
    description: 'nest g module tasks && nest g controller tasks && nest g service tasks',
    status: 'done',
    created_at: '2026-03-18',
  },
  {
    id: uuidv4(),
    title: 'Define Task entity',
    description: 'Fields: id (uuid), title, description, status, created_at with TypeORM decorators',
    status: 'in-progress',
    created_at: '2026-03-19',
  },
  {
    id: uuidv4(),
    title: 'Implement CRUD service methods',
    description: 'findAll, findOne, create, update, remove — inject TaskRepository',
    status: 'in-progress',
    created_at: '2026-03-19',
  },
  {
    id: uuidv4(),
    title: 'Add DTO validation',
    description: '@IsNotEmpty() on title, @IsOptional() on description using class-validator',
    status: 'open',
    created_at: '2026-03-20',
  },
  {
    id: uuidv4(),
    title: 'Write Postman collection',
    description: 'Document all REST endpoints with sample bodies and expected responses',
    status: 'open',
    created_at: '2026-03-20',
  },
  {
    id: uuidv4(),
    title: 'Connect React frontend to API',
    description: 'Replace mock data with fetch() / axios calls to localhost:3000',
    status: 'open',
    created_at: '2026-03-20',
  },
];

const TaskContext = createContext(null);

export function TaskProvider({ children }) {
  const [tasks, setTasks] = useState(INITIAL_TASKS);
  const [toast, setToast] = useState(null);
  let toastTimer = null;

  const showToast = useCallback((method, message, type = 'success') => {
    clearTimeout(toastTimer);
    setToast({ method, message, type });
    // eslint-disable-next-line react-hooks/exhaustive-deps
    toastTimer = setTimeout(() => setToast(null), 2800);
  }, []);

  const addTask = useCallback((data) => {
    const task = {
      id: uuidv4(),
      title: data.title.trim(),
      description: data.description?.trim() || '',
      status: data.status || 'open',
      created_at: new Date().toISOString().slice(0, 10),
    };
    setTasks(prev => [task, ...prev]);
    showToast('POST /tasks', `201 Created — "${task.title.slice(0, 28)}"`, 'success');
    return task;
  }, [showToast]);

  const updateTask = useCallback((id, updates) => {
    setTasks(prev => prev.map(t => t.id === id ? { ...t, ...updates } : t));
    showToast(`PATCH /tasks/${id.slice(0, 6)}`, '200 OK — Task updated', 'info');
  }, [showToast]);

  const toggleTask = useCallback((id) => {
    setTasks(prev => prev.map(t => {
      if (t.id !== id) return t;
      const newStatus = t.status === 'done' ? 'open' : 'done';
      showToast(`PATCH /tasks/${id.slice(0, 6)}`, newStatus === 'done' ? '200 Marked complete' : '200 Reopened', 'info');
      return { ...t, status: newStatus };
    }));
  }, [showToast]);

  const deleteTask = useCallback((id) => {
    setTasks(prev => prev.filter(t => t.id !== id));
    showToast(`DELETE /tasks/${id.slice(0, 6)}`, '204 No Content', 'danger');
  }, [showToast]);

  return (
    <TaskContext.Provider value={{ tasks, addTask, updateTask, toggleTask, deleteTask, toast }}>
      {children}
    </TaskContext.Provider>
  );
}

export function useTasks() {
  const ctx = useContext(TaskContext);
  if (!ctx) throw new Error('useTasks must be inside TaskProvider');
  return ctx;
}
